class Solution:
    def countQuadruplets(self, nums):
        from itertools import combinations
        count = 0
        for i, j, k, l in combinations(range(len(nums)), 4):
            if nums[i] + nums[j] + nums[k] == nums[l]:
                count += 1
        return count

