class Solution:
    def countQuadruplets(self, nums):
        from collections import Counter
        n = len(nums)
        count = 0
        for k in range(2, n - 1):
            after = Counter(nums[k + 1:])
            for j in range(1, k):
                base = nums[j] + nums[k]
                for i in range(j):
                    count += after.get(base + nums[i], 0)
        return count

