var countQuadruplets = function(nums) {
    const n = nums.length;
    let count = 0;
    for (let k = 2; k < n - 1; k++) {
        const after = new Map();
        for (let l = k + 1; l < n; l++) {
            after.set(nums[l], (after.get(nums[l]) || 0) + 1);
        }
        for (let j = 1; j < k; j++) {
            const base = nums[j] + nums[k];
            for (let i = 0; i < j; i++) {
                count += after.get(base + nums[i]) || 0;
            }
        }
    }
    return count;
};
